const raw = $json.choices?.[0]?.message?.content || '';
const sessionData = $('Code Merge Session1').first().json;

let parsed;
try {
  const cleaned = raw.replace(/```json/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    intent: 'unknown',
    process_status: 'complete',
    task_name: '', subject: '', task_type: 'Personal',
    deadline_date: '', deadline_time: '', has_time: false,
    status: 'pending',
    reply_message: 'ขอโทษครับ ระบบขัดข้องชั่วคราว กรุณาลองใหม่อีกครั้ง'
  };
}

const intent        = parsed.intent         || 'unknown';
const processStatus = parsed.process_status || 'complete';

// MERGE session + ข้อมูลใหม่จาก LLM
const taskName     = parsed.task_name     || sessionData.session_task_name     || '';
const subject      = parsed.subject       || sessionData.session_subject       || '';
const taskType     = parsed.task_type     || sessionData.session_task_type     || 'Personal';
const deadlineDate = parsed.deadline_date || sessionData.session_deadline_date || '';
const deadlineTime = parsed.deadline_time || sessionData.session_deadline_time || '';

// has_time: ใช้ parsed.has_time ก่อน ถ้าไม่มีค่อยดูจาก deadlineTime
let hasTime = false;
if (typeof parsed.has_time === 'boolean') {
  hasTime = parsed.has_time;
} else if (typeof parsed.has_time === 'string') {
  hasTime = parsed.has_time === 'true';
} else {
  hasTime = !!(deadlineTime && String(deadlineTime).trim() !== '');
}

// rowStatus:
// 'session'  = incomplete รอ user ตอบคำถาม
// 'pending'  = งานจริง
const rowStatus = (intent === 'add_task' && processStatus === 'incomplete')
  ? 'session'
  : 'pending';

let replyMessage = parsed.reply_message || '';

if (intent === 'add_task' && processStatus === 'complete' && !parsed.reply_message) {
  replyMessage = hasTime
    ? `✅ บันทึกงานแล้วครับ!\n\n📌 ${taskName}\n📚 ${subject || '-'}\n🗂️ ${taskType}\n📅 ${deadlineDate} เวลา ${deadlineTime}\n\nจะแจ้งเตือนก่อน 1 ชม. และ 15 นาทีนะครับ 🔔`
    : `✅ บันทึกงานแล้วครับ!\n\n📌 ${taskName}\n📚 ${subject || '-'}\n🗂️ ${taskType}\n📅 ${deadlineDate}\n\nจะแจ้งเตือนก่อน 24 ชม. และ 1 ชม. นะครับ 🔔`;
}
if (intent === 'complete_task' && !parsed.reply_message) {
  replyMessage = `กำลังอัปเดตงาน "${taskName}" เป็น done ✅`;
}
if (intent === 'view_tasks' && !parsed.reply_message) {
  replyMessage = 'กำลังดึงรายการงานค้างให้ครับ 📋';
}
if (intent === 'delete_task' && !parsed.reply_message) {
  replyMessage = `กำลังลบงาน "${taskName}" ให้ครับ...`;
}
if (intent === 'edit_task' && !parsed.reply_message) {
  replyMessage = `กำลังแก้ไขงาน "${taskName}" ให้ครับ...`;
}
if (intent === 'unknown' && !parsed.reply_message) {
  replyMessage = '❓ ขอโทษครับ ไม่เข้าใจคำสั่งนี้\n\nลองพิมพ์แบบนี้นะครับ:\n• "มีแข่งพรุ่งนี้ 10 โมง"\n• "ส่ง Report CSI403 วันที่ 20"\n• "ทำ Assignment เสร็จแล้ว"\n• "ลบงาน [ชื่องาน]" หรือ "เลื่อนงาน [ชื่องาน] เป็น [วัน]"\n• "มีงานอะไรบ้าง"';
}

return [{
  json: {
    intent,
    process_status: processStatus,
    user_id:    sessionData.userId,
    replyToken: sessionData.replyToken,
    task_name:     taskName,
    subject,
    task_type:     taskType,
    deadline_date: deadlineDate,
    deadline_time: deadlineTime,
    has_time:      hasTime ? 'true' : 'false',
    notified_1h:   'false',
    notified_15m:  'false',
    status:        rowStatus,
    reply_message: replyMessage,
    created_at:    new Date().toISOString()
  }
}];

const found = $input.all();
const original = $('Code Parse Gemini1').first().json;

if (found.length === 0 || found[0].json.row_number == null) {
  return [{
    json: {
      user_id:      original.user_id,
      replyToken:   original.replyToken,
      reply_message:`❌ ไม่พบงาน "${original.task_name}" ในรายการ หรืองานนั้นเสร็จแล้ว`,
      row_number:   null,
      skip_update:  true
    }
  }];
}

return [{
  json: {
    user_id:      original.user_id,
    replyToken:   original.replyToken,
    task_name:    found[0].json.task_name,
    reply_message:`✅ อัปเดตสถานะงาน "${found[0].json.task_name}" เป็น done แล้วครับ!`,
    row_number:   found[0].json.row_number,
    skip_update:  false
  }
}];

const rows = $input.all();
const original = $('Code Parse Gemini1').first().json;

let message = '';

// กรอง: เอาเฉพาะ pending (double-check กันพลาด)
const pendingRows = rows.filter(r =>
  String(r.json.status).toLowerCase() === 'pending'
);

if (pendingRows.length === 0) {
  message = '✅ ตอนนี้ไม่มีงานค้างเลยครับ ทำครบหมดแล้ว! 🎉';
} else {
  const tasks = pendingRows.map(r => r.json).map(t => {
    const timeStr = t.deadline_time && String(t.deadline_time).trim() !== ''
      ? String(t.deadline_time).trim()
      : '07:00';
    t._deadline = new Date(`${t.deadline_date}T${timeStr}:00+07:00`);
    return t;
  }).filter(t => !isNaN(t._deadline));

  const sorted = tasks.sort((a, b) => a._deadline - b._deadline);

  if (sorted.length === 0) {
    message = '✅ ตอนนี้ไม่มีงานค้างเลยครับ 🎉';
  } else {
    const now = new Date();

    // แยก overdue vs upcoming
    const overdue  = sorted.filter(t => t._deadline < now);
    const upcoming = sorted.filter(t => t._deadline >= now);

    message = `📋 งานค้างทั้งหมด (${sorted.length} งาน)\n`;
    message += `─────────────────\n`;

    if (overdue.length > 0) {
      message += `\n🔴 เลยกำหนดแล้ว (${overdue.length})\n`;
      overdue.forEach((task, i) => {
        const dl = task._deadline;
        const dlStr = dl.toLocaleDateString('th-TH', {
          month: 'short', day: 'numeric',
          hour: '2-digit', minute: '2-digit',
          timeZone: 'Asia/Bangkok'
        });
        message += `${i+1}. ❗ ${task.task_name}\n`;
        message += `   📚 ${task.subject || '-'} | 📅 ${dlStr}\n`;
      });
    }

    if (upcoming.length > 0) {
      message += `\n📌 งานที่ยังไม่ถึงกำหนด (${upcoming.length})\n`;
      upcoming.forEach((task, i) => {
        const dl = task._deadline;
        const now2 = new Date();
        const minsLeft  = Math.round((dl - now2) / 60000);
        const hoursLeft = minsLeft / 60;
        const daysLeft  = hoursLeft / 24;

        let urgency = '';
        if (minsLeft < 60)       urgency = '🚨';
        else if (hoursLeft < 24) urgency = '🟠';
        else if (daysLeft <= 3)  urgency = '🟡';
        else                     urgency = '🟢';

        const dlStr = dl.toLocaleDateString('th-TH', {
          month: 'short', day: 'numeric',
          hour: '2-digit', minute: '2-digit',
          timeZone: 'Asia/Bangkok'
        });

        const timeLeft = daysLeft >= 1
          ? `อีก ${Math.floor(daysLeft)} วัน`
          : `อีก ${Math.floor(hoursLeft)} ชม.`;

        message += `${i+1}. ${urgency} ${task.task_name}\n`;
        message += `   📚 ${task.subject || '-'} | ⏰ ${dlStr} (${timeLeft})\n`;
      });
    }

    message += `\n─────────────────\nพิมพ์ "ทำ [ชื่องาน] เสร็จแล้ว" เพื่ออัปเดตนะครับ ✏️`;
  }
}

return [{
  json: {
    user_id:       original.user_id,
    replyToken:    original.replyToken,
    reply_message: message
  }
}];

const original = $input.first().json;
return [{
  json: {
    user_id:       original.user_id,
    replyToken:    original.replyToken,
    reply_message: '❓ ขอโทษครับ ไม่เข้าใจคำสั่งนี้\n\nลองพิมพ์แบบนี้นะครับ:\n• "มีประชุม 10 โมงพรุ่งนี้" → แจ้งเตือน 3 ชม.+15 นาทีก่อน\n• "กำหนดส่ง Report CSI403 วันที่ 20" → แจ้งเตือน 24 ชม.+1 ชม.ก่อน\n• "ทำ Assignment CSI401 เสร็จแล้ว"\n• "มีงานอะไรบ้าง"'
  }
}];

const item = $input.first().json;
const base = $('Code Parse Gemini1').first().json;

const replyMsg   = item.reply_message || base.reply_message || 'ดำเนินการเรียบร้อยครับ ✅';
const replyToken = item.replyToken    || base.replyToken    || '';

return [{ json: { replyToken, reply_message: replyMsg } }];

const items = $input.all();
const results = [];

// เวลาปัจจุบันในโซนไทย
const nowParts = new Intl.DateTimeFormat('en-GB', {
  timeZone: 'Asia/Bangkok',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  hourCycle: 'h23',
}).formatToParts(new Date());

const getPart = (type) => nowParts.find(p => p.type === type)?.value || '';

const nowY = Number(getPart('year'));
const nowM = Number(getPart('month'));
const nowD = Number(getPart('day'));
const nowH = Number(getPart('hour'));
const nowMin = Number(getPart('minute'));

const nowUtcMs = Date.UTC(nowY, nowM - 1, nowD, nowH, nowMin);

for (const item of items) {
  const task = item.json;

  if (!task.task_id) continue;
  if (!task.user_id) continue;
  if (!task.deadline_date) continue;
  if (String(task.status).toLowerCase() !== 'pending') continue;

  // deadline_date ต้องเป็น YYYY-MM-DD
  const dateStr = String(task.deadline_date).trim();
  const dateParts = dateStr.split('-');
  if (dateParts.length !== 3) continue;

  const year = Number(dateParts[0]);
  const month = Number(dateParts[1]);
  const day = Number(dateParts[2]);

  // ถ้าไม่มีเวลา ใช้ 07:00
  let hour = 7;
  let minute = 0;

  if (task.deadline_time && String(task.deadline_time).trim() !== '') {
    const rawTime = String(task.deadline_time).trim();
    const timeParts = rawTime.split(':');

    if (timeParts.length === 2) {
      hour = Number(timeParts[0]);
      minute = Number(timeParts[1]);
    }
  }

  if (
    Number.isNaN(year) ||
    Number.isNaN(month) ||
    Number.isNaN(day) ||
    Number.isNaN(hour) ||
    Number.isNaN(minute)
  ) {
    continue;
  }

  const deadlineUtcMs = Date.UTC(year, month - 1, day, hour, minute);
  const minsLeft = Math.round((deadlineUtcMs - nowUtcMs) / 60000);

  // เลยเวลาแล้ว ข้าม
  if (minsLeft <= 0) continue;

  const notified1h = String(task.notified_1h).toLowerCase() === 'true';
  const notified15m = String(task.notified_15m).toLowerCase() === 'true';

  let notifyKey = '';
  let prefix = '';

  // ก่อน 15 นาที
  if (minsLeft <= 15 && !notified15m) {
    notifyKey = 'notified_15m';
    prefix = '⏰ อีก 15 นาทีจะถึงกำหนดแล้ว';
  }
  // ก่อน 1 ชั่วโมง
  else if (minsLeft <= 60 && !notified1h) {
    notifyKey = 'notified_1h';
    prefix = '🔔 อีก 1 ชั่วโมงจะถึงกำหนดแล้ว';
  } else {
    continue;
  }

  const hh = String(hour).padStart(2, '0');
  const mm = String(minute).padStart(2, '0');

  const pushMessage =
    `${prefix}\n\n` +
    `📌 ${task.task_name || '-'}\n` +
    `📚 ${task.subject || '-'}\n` +
    `🗂️ ${task.task_type || '-'}\n` +
    `📅 กำหนด: ${dateStr} ${hh}:${mm}`;

  results.push({
    json: {
      task_id: task.task_id,
      user_id: task.user_id,
      notify_key: notifyKey,
      push_message: pushMessage,
      mins_left: minsLeft
    }
  });
}

return results;

const items = $input.all();
const now = new Date();

const userMap = {};
for (const item of items) {
  const task = item.json;
  // กรองเฉพาะ pending (ไม่เอา done, session)
  if (!task.user_id || !task.deadline_date) continue;
  if (String(task.status).toLowerCase() !== 'pending') continue;

  const timeStr = task.deadline_time && String(task.deadline_time).trim() !== ''
    ? String(task.deadline_time).trim()
    : '07:00';
  task._deadline = new Date(`${task.deadline_date}T${timeStr}:00+07:00`);
  if (isNaN(task._deadline)) continue;

  if (!userMap[task.user_id]) userMap[task.user_id] = [];
  userMap[task.user_id].push(task);
}

const results = [];
for (const [userId, tasks] of Object.entries(userMap)) {
  const sorted = tasks.sort((a, b) => a._deadline - b._deadline);

  const overdue  = sorted.filter(t => t._deadline < now);
  const upcoming = sorted.filter(t => {
    const daysLeft = (t._deadline - now) / 86400000;
    return daysLeft >= 0 && daysLeft <= 7;
  });
  const allPending = sorted.filter(t => t._deadline >= now);

  let message = `🌅 อรุณสวัสดิ์ครับ! สรุปงานประจำวัน\n`;
  message += `📅 ${now.toLocaleDateString('th-TH', {
    weekday:'long', year:'numeric', month:'long', day:'numeric',
    timeZone:'Asia/Bangkok'
  })}\n`;
  message += `─────────────────\n`;

  if (overdue.length > 0) {
    message += `\n🔴 เลยกำหนดแล้ว! (${overdue.length} งาน)\n`;
    overdue.forEach(task => {
      const dl = task._deadline;
      const dlStr = dl.toLocaleDateString('th-TH', {month:'short', day:'numeric', hour:'2-digit', minute:'2-digit', timeZone:'Asia/Bangkok'});
      message += `❗ ${task.task_name} (${task.subject || '-'}) — ${dlStr}\n`;
    });
  }

  if (upcoming.length > 0) {
    message += `\n⚡ งาน deadline ใน 7 วัน (${upcoming.length} งาน)\n`;
    upcoming.forEach(task => {
      const dl = task._deadline;
      const daysLeft  = Math.round((dl - now) / 86400000);
      const hoursLeft = Math.round((dl - now) / 3600000);
      const dlStr = dl.toLocaleDateString('th-TH', {month:'short', day:'numeric', hour:'2-digit', minute:'2-digit', timeZone:'Asia/Bangkok'});
      const urgency = hoursLeft < 3 ? '🔴' : hoursLeft < 6 ? '🟠' : daysLeft <= 1 ? '🟡' : '🟢';
      message += `${urgency} ${task.task_name} (${task.subject || '-'}) — ${dlStr}\n`;
    });
  } else if (overdue.length === 0) {
    message += `\n✅ ไม่มีงาน deadline ใน 7 วันข้างหน้า\n`;
  }

  message += `\n─────────────────`;
  message += `\n📊 งานค้างรวม: ${allPending.length} งาน`;
  message += `\nสู้ๆ นะครับ! 💪`;

  results.push({ json: { user_id: userId, push_message: message } });
}

if (results.length === 0) return [];
return results;

const editFields = $('Edit Fields').first().json;
const sessionRows = $input.all();

// หา row ที่เป็น session จริงๆ (status='session' = incomplete turn ก่อนหน้า)
const sessionRow = sessionRows.find(r =>
  String(r.json.status).toLowerCase() === 'session'
) || null;

const session = sessionRow ? sessionRow.json : {};

return [{
  json: {
    userId:       editFields.userId,
    replyToken:   editFields.replyToken,
    text:         editFields.text,
    session_task_name:     session.task_name     || '',
    session_subject:       session.subject       || '',
    session_task_type:     session.task_type     || '',
    session_deadline_date: session.deadline_date || '',
    session_deadline_time: session.deadline_time || '',
    session_has_time:      session.has_time      || '',
    has_pending_session:   sessionRow ? 'true' : 'false'
  }
}];

const rows = $input.all();
const parsed = $('Code Parse Gemini1').first().json;

const newDate = parsed.deadline_date || '';
const newTime = parsed.deadline_time || '';
const newTaskType = parsed.task_type || '';

// Only check time conflict for Meeting tasks that have a time
const shouldCheckTime = newTaskType === 'Meeting' && newTime !== '';

let conflicts = [];

if (shouldCheckTime) {
  const [newH, newM] = newTime.split(':').map(Number);
  const newMins = newH * 60 + newM;

  for (const row of rows) {
    const t = row.json;
    if (!t.deadline_time || t.deadline_time === '') continue;
    if (t.task_name === parsed.task_name) continue; // skip same task

    const [h, m] = String(t.deadline_time).split(':').map(Number);
    const existMins = h * 60 + m;
    const diff = Math.abs(newMins - existMins);

    if (diff < 60) { // within 60 minutes = conflict
      conflicts.push({
        task_name: t.task_name,
        deadline_time: t.deadline_time,
        subject: t.subject || '-'
      });
    }
  }
}

const hasConflict = conflicts.length > 0;

if (hasConflict) {
  const conflictList = conflicts.map(c =>
    `• ${c.task_name} (${c.subject}) เวลา ${c.deadline_time}`
  ).join('\n');

  const warningMsg =
    `⚠️ พบนัดซ้อนในวันที่ ${newDate}!\n\n` +
    `งานที่ทับกัน:\n${conflictList}\n\n` +
    `ต้องการบันทึก "${parsed.task_name}" เวลา ${newTime} ต่อไหมครับ?`;

  return [{
    json: {
      has_conflict: "true",
      user_id:      parsed.user_id,
      replyToken:   parsed.replyToken,
      reply_message: warningMsg,
      quick_reply_type: 'conflict_confirm',
      // Pass through all task data so we can save later
      pending_task: JSON.stringify({
        user_id:       parsed.user_id,
        task_name:     parsed.task_name,
        subject:       parsed.subject,
        task_type:     parsed.task_type,
        deadline_date: parsed.deadline_date,
        deadline_time: parsed.deadline_time,
        has_time:      parsed.has_time,
        created_at:    parsed.created_at
      })
    }
  }];
}

// No conflict — pass through for normal save
return [{
  json: {
    has_conflict: "false",
    ...parsed
  }
}];

const found = $input.all();
const original = $('Code Parse Gemini1').first().json;

if (found.length === 0 || found[0].json.row_number == null) {
  return [{
    json: {
      user_id:      original.user_id,
      replyToken:   original.replyToken,
      reply_message: `❌ ไม่พบงาน "${original.task_name}" ในรายการครับ\n\nลองพิมพ์ "มีงานอะไรบ้าง" เพื่อดูชื่องานที่ถูกต้องนะครับ`,
      skip_delete:  true,
      row_number:   null
    }
  }];
}

const task = found[0].json;
return [{
  json: {
    user_id:      original.user_id,
    replyToken:   original.replyToken,
    task_name:    task.task_name,
    reply_message: `🗑️ ลบงาน "${task.task_name}" เรียบร้อยแล้วครับ!`,
    row_number:   task.row_number,
    skip_delete:  false
  }
}];

const found = $input.all();
const original = $('Code Parse Gemini1').first().json;

if (found.length === 0 || found[0].json.row_number == null) {
  return [{
    json: {
      user_id:      original.user_id,
      replyToken:   original.replyToken,
      reply_message: `❌ ไม่พบงาน "${original.task_name}" ในรายการครับ\n\nลองพิมพ์ "มีงานอะไรบ้าง" เพื่อดูชื่องานที่ถูกต้องนะครับ`,
      skip_edit:    true,
      row_number:   null
    }
  }];
}

const task = found[0].json;
const newDate = original.deadline_date || task.deadline_date;
const newTime = original.deadline_time || task.deadline_time || '';
const hasTime = newTime !== '';

let changeDesc = '';
if (original.deadline_date && original.deadline_date !== task.deadline_date) {
  changeDesc += `📅 วันที่: ${task.deadline_date} → ${newDate}\n`;
}
if (original.deadline_time && original.deadline_time !== task.deadline_time) {
  changeDesc += `⏰ เวลา: ${task.deadline_time || 'ไม่มี'} → ${newTime}\n`;
}
if (!changeDesc) changeDesc = `📅 ${newDate}${hasTime ? ' ' + newTime : ''}\n`;

return [{
  json: {
    user_id:        original.user_id,
    replyToken:     original.replyToken,
    task_name:      task.task_name,
    reply_message:  `✏️ แก้ไขงาน "${task.task_name}" เรียบร้อยแล้วครับ!\n\n${changeDesc}`,
    row_number:     task.row_number,
    new_deadline_date: newDate,
    new_deadline_time: newTime,
    new_has_time:   hasTime ? 'true' : 'false',
    skip_edit:      false
  }
}];
